class CloudAPIClient {
    private let baseURL = "https://api.example.com"
    private let httpClient = HTTPClient.shared
    
    func getDevices(completion: @escaping (Result<[Device], HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices"
        httpClient.requestJSON(url: url, responseType: [Device].self, completion: completion)
    }
    
    func updateDevice(deviceId: String, data: DeviceUpdate, completion: @escaping (Result<Device, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices/\(deviceId)"
        
        do {
            let encoder = JSONEncoder()
            let jsonData = try encoder.encode(data)
            
            httpClient.requestJSON(url: url, method: .put, body: jsonData, responseType: Device.self, completion: completion)
        } catch {
            completion(.failure(.decodingError))
        }
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<AuthResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/auth/login"
        let credentials = ["username": username, "password": password]
        
        do {
            let encoder = JSONEncoder()
            let jsonData = try encoder.encode(credentials)
            
            httpClient.requestJSON(url: url, method: .post, body: jsonData, responseType: AuthResponse.self, completion: completion)
        } catch {
            completion(.failure(.decodingError))
        }
    }
}

class IoTDeviceClient {
    private let httpClient = HTTPClient.shared
    
    func getDeviceStatus(ipAddress: String, completion: @escaping (Result<IoTDeviceStatus, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/status"
        httpClient.requestJSON(url: url, responseType: IoTDeviceStatus.self, completion: completion)
    }
    
    func sendCommand(ipAddress: String, command: IoTCommand, completion: @escaping (Result<IoTCommandResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/command"
        
        do {
            let encoder = JSONEncoder()
            let jsonData = try encoder.encode(command)
            
            httpClient.requestJSON(url: url, method: .post, body: jsonData, responseType: IoTCommandResponse.self, completion: completion)
        } catch {
            completion(.failure(.decodingError))
        }
    }
    
    func updateSettings(ipAddress: String, settings: IoTSettings, completion: @escaping (Result<Data, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/settings"
        
        do {
            let encoder = JSONEncoder()
            let jsonData = try encoder.encode(settings)
            
            httpClient.request(url: url, method: .put, body: jsonData, completion: completion)
        } catch {
            completion(.failure(.decodingError))
        }
    }
    
    func discoverDevices(subnet: String = "192.168.1", completion: @escaping ([String]) -> Void) {
        var availableDevices: [String] = []
        let dispatchGroup = DispatchGroup()
        let queue = DispatchQueue(label: "com.app.discovery", attributes: .concurrent)
        
        for i in 1...254 {
            dispatchGroup.enter()
            let ipAddress = "\(subnet).\(i)"
            
            queue.async {
                self.pingDevice(ipAddress: ipAddress) { isAvailable in
                    if isAvailable {
                        availableDevices.append(ipAddress)
                    }
                    dispatchGroup.leave()
                }
            }
        }
        
        dispatchGroup.notify(queue: .main) {
            completion(availableDevices)
        }
    }
    
    private func pingDevice(ipAddress: String, completion: @escaping (Bool) -> Void) {
        let url = "http://\(ipAddress)/ping"
        
        httpClient.request(url: url, method: .get) { result in
            switch result {
            case .success:
                completion(true)
            case .failure:
                completion(false)
            }
        }
    }
}

