class ViewController: UIViewController {
    private let cloudAPI = CloudAPIClient()
    private let iotClient = IoTDeviceClient()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        
        testCloudAPI()
        testIoTDevice()
        discoverLocalDevices()
    }
    
    private func testCloudAPI() {
        cloudAPI.authenticate(username: "user@example.com", password: "password") { result in
            switch result {
            case .success(let authResponse):
                print("Authenticated: \(authResponse.token)")
                self.fetchDevices()
            case .failure(let error):
                print("Auth error: \(error)")
            }
        }
    }
    
    private func fetchDevices() {
        cloudAPI.getDevices { result in
            switch result {
            case .success(let devices):
                print("Fetched \(devices.count) devices")
                for device in devices {
                    print("Device: \(device.name) - \(device.status)")
                }
            case .failure(let error):
                print("Fetch devices error: \(error)")
            }
        }
    }
    
    private func testIoTDevice() {
        let deviceIP = "192.168.1.100"
        
        iotClient.getDeviceStatus(ipAddress: deviceIP) { result in
            switch result {
            case .success(let status):
                print("Device status: Online=\(status.online), Temp=\(status.temperature ?? 0)")
            case .failure(let error):
                print("IoT device error: \(error)")
            }
        }
        
        let command = IoTCommand(action: "turnOn", parameters: ["brightness": "80"])
        iotClient.sendCommand(ipAddress: deviceIP, command: command) { result in
            switch result {
            case .success(let response):
                print("Command response: \(response.message)")
            case .failure(let error):
                print("Command error: \(error)")
            }
        }
    }
    
    private func discoverLocalDevices() {
        iotClient.discoverDevices(subnet: "192.168.1") { devices in
            print("Discovered \(devices.count) devices:")
            for device in devices {
                print("- \(device)")
            }
        }
    }
}